<span class="line"><span style="color:#EBA0AC;">    path</span><span style="color:#94E2D5;">:</span><span style="color:#94E2D5;"> &amp;</span><span style="color:#F9E2AF;font-style:italic;">Path</span><span style="color:#9399B2;">,</span></span>
